form:Form.form:Scripts:
		
function validar_clave()
{
	if (Ctrl('d_clave').GetCValue() == "" || Ctrl('d_clave_vieja').GetCValue() == "" || Ctrl('d_clave2').GetCValue() == "")
	{
		alert('La clave actual y la clave nueva son requeridas');
		return false;		
	}
	if (Ctrl('d_clave').GetCValue() != Ctrl('d_clave2').GetCValue())
	{
		alert('Las claves no concuerdan');
		return false;
  }
	if (Ctrl('d_clave_vieja').GetCValue() == Ctrl('d_clave').GetCValue())
	{
		alert('La clave nueva es igual a la actual');
		return false;
	}
	return true;
}

function validar_email()
{
	if (Ctrl('d_email').GetCValue() == "" || Ctrl('d_email2').GetCValue() == "" || Ctrl('d_email_viejo').GetCValue() == "")
	{
		alert('El E-Mail actual y el nuevo son requeridos');
		return false;
  }
	if (Ctrl('d_email').GetCValue() != Ctrl('d_email2').GetCValue())
	{
		alert('Los E-Mails no concuerdan');
		return false;
  }
	if (Ctrl('d_email_viejo').GetCValue() == Ctrl('d_email').GetCValue())
	{
		alert('El E-Mail nuevo es igual al actual');
		return false;
	}
	if (!val_mail(Ctrl('d_email')))
	{
		return false;
	}

	return true;
}            


function ONLOAD()
{	
	Ctrl("user").SetXValue("Usuario: " + Ctrl("nombre").GetXValue() + " " + Ctrl("apellido").GetXValue());
}

function val_mail(me)
{
	var mail = me.GetXValue();

	if (mail.split("@").length != 2)
	{
		alert("El mail es inválido");
		return false;
	}

	var array_mail = mail.split("@")
	if (array_mail[1].indexOf(".") < 0)
	{
		alert("El mail es inválido");
		return false;
	}

	/* Verificar la existencia de caracteres. ( ) < > @ , ; : \ " . [ ] */
	var specialChars="\\(\\)<>@,;:\\\\\\\"\\.\\[\\]";
	var validChars="\[^\\s" + specialChars + "\]";
	var quotedUser="(\"[^\"]*\")";

	var atom=validChars + '+';
	var word="(" + atom + "|" + quotedUser + ")";
	var userPat=new RegExp("^" + word + "(\\." + word + ")*$");


	if (array_mail[0].match(userPat)==null) {
	alert("El mail es inválido")
	return false
	}

	if (array_mail[1].match(userPat)==null) {
	alert("El mail es inválido")
	return false
	}

	return true;
}
